const stdout = String($json.stdout ?? '');
const stderr = String($json.stderr ?? '');
const rawExit = $json.exitCode ?? $json.code;
const exitCode = rawExit === undefined || rawExit === null || rawExit === '' ? 0 : Number(rawExit);
const commandError = String($json.error?.message ?? $json.error ?? $json.message ?? '');
const lines = stdout.trim().split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
let parsed = null;
for (let i = lines.length - 1; i >= 0; i--) {
  try {
    const candidate = JSON.parse(lines[i]);
    if (candidate && typeof candidate === 'object') {
      parsed = candidate;
      break;
    }
  } catch (error) {}
}
const toInt = (value) => Number.isFinite(Number(value)) ? Number(value) : 0;
const tail = (value, max = 2500) => {
  const text = String(value ?? '');
  return text.length > max ? text.slice(text.length - max) : text;
};
let payload;
let parseError = '';
if (parsed) {
  const summary = parsed.summary || {
    total: toInt(parsed.total),
    pass: toInt(parsed.pass),
    warn: toInt(parsed.warn),
    fail: toInt(parsed.fail),
  };
  const parsedOk = parsed.ok === undefined ? toInt(summary.fail) === 0 : parsed.ok === true;
  payload = {
    ok: parsedOk && toInt(summary.fail) === 0,
    run_id: parsed.run_id || '',
    target_name: parsed.target_name || '台灣人壽官網',
    summary,
    latest_json: parsed.latest_json || parsed.json || '',
    latest_md: parsed.latest_md || '',
    email_sent: parsed.email_sent || false,
    summary_text: parsed.summary_text || `PASS=${summary.pass} WARN=${summary.warn} FAIL=${summary.fail}`,
  };
} else {
  parseError = 'Python stdout 最後幾行找不到可解析的 JSON payload';
  payload = {
    ok: false,
    run_id: '',
    target_name: '台灣人壽官網',
    summary: { total: 0, pass: 0, warn: 0, fail: 1 },
    latest_json: '',
    latest_md: '',
    email_sent: false,
    summary_text: parseError,
  };
}
const failCount = toInt(payload.summary.fail);
const warnCount = toInt(payload.summary.warn);
const nonZeroExit = Number.isFinite(exitCode) && exitCode !== 0;
const shouldAlert = !payload.ok || failCount > 0 || warnCount > 0 || nonZeroExit || commandError.length > 0 || Boolean(parseError);
const problemChecks = Array.isArray(parsed?.checks) ? parsed.checks.filter((check) => check.status !== 'pass').slice(0, 10) : [];
const checkText = problemChecks.map((check) => `- [${check.status}] ${check.id || ''} ${check.name || ''}: ${check.detail || ''}`).join('\n');
const diagnosticText = [
  parseError ? `解析錯誤：${parseError}` : '',
  nonZeroExit ? `Exit code：${exitCode}` : '',
  commandError ? `Command error：${commandError}` : '',
  stderr ? `stderr tail:\n${tail(stderr)}` : '',
  !parsed && stdout ? `stdout tail:\n${tail(stdout)}` : '',
].filter(Boolean).join('\n\n');
const emailSubject = `[台壽官網巡檢] ${shouldAlert ? '異常' : '正常'} fail=${failCount} warn=${warnCount}`;
const emailText = [
  `${payload.target_name}巡檢${shouldAlert ? '異常' : '結果'}`,
  payload.summary_text,
  `Run ID：${payload.run_id || '(無)'}`,
  `JSON：${payload.latest_json || '(未產生)'}`,
  `Markdown：${payload.latest_md || '(未產生)'}`,
  checkText ? `異常明細:\n${checkText}` : '',
  diagnosticText,
  '請登入巡檢主機查看完整報告與截圖。',
].filter(Boolean).join('\n\n');
return [{
  json: {
    ...payload,
    should_alert: shouldAlert,
    alert_score: shouldAlert ? 1 : 0,
    command_exit_code: Number.isFinite(exitCode) ? exitCode : null,
    command_error: commandError,
    parse_error: parseError,
    stdout_tail: tail(stdout),
    stderr_tail: tail(stderr),
    email_subject: emailSubject,
    email_text: emailText,
  },
}];
